from dataclasses import dataclass, field

@dataclass
class SessionTelemetry:
    session_id: str
    turns: list[dict] = field(default_factory=list)

    def record_turn(self, turn_tel: TurnTelemetry) -> None:
        self.turns.append(turn_tel.finish())

    def summary(self) -> dict:
        if not self.turns:
            return {"session_id": self.session_id, "turns": 0}
        return {
            "session_id": self.session_id,
            "total_turns": len(self.turns),
            "total_llm_calls": sum(t["llm_calls"] for t in self.turns),
            "total_tool_calls": sum(t["tool_calls"] for t in self.turns),
            "total_tool_errors": sum(t["tool_errors"] for t in self.turns),
            "total_input_tokens": sum(t["input_tokens"] for t in self.turns),
            "total_output_tokens": sum(t["output_tokens"] for t in self.turns),
            "max_context_tokens": max(t["context_tokens"] for t in self.turns),
            "total_latency_ms": sum(t["latency_ms"] for t in self.turns),
            "stop_reasons": [t["stop_reason"] for t in self.turns],
            # session ended cleanly if the last turn stopped with end_turn
            "clean_end": self.turns[-1]["stop_reason"] == "end_turn",
        }

# Detect sessions that hit the max iteration limit
def find_runaway_sessions(sessions: list[SessionTelemetry]) -> list[str]:
    return [
        s.session_id
        for s in sessions
        if any(t["stop_reason"] == "max_iterations" for t in s.turns)
    ]

from dataclasses import dataclass

@dataclass
class AgentAlertThresholds:
    max_iterations_rate: float = 0.03     # > 3% of turns hit iteration cap
    avg_turns_per_session: float = 8.0    # sessions averaging > 8 turns suggest confused agent
    tool_error_per_turn: float = 0.05     # > 5% of turns have a tool error
    context_token_p95: int = 3500         # p95 context tokens > 3500 (near typical limits)

def check_agent_alerts(
    sessions: list[SessionTelemetry],
    thresholds: AgentAlertThresholds = AgentAlertThresholds(),
) -> list[str]:
    alerts = []
    all_turns = [t for s in sessions for t in s.turns]
    if not all_turns:
        return alerts

    max_iter_rate = sum(1 for t in all_turns if t["stop_reason"] == "max_iterations") / len(all_turns)
    if max_iter_rate > thresholds.max_iterations_rate:
        alerts.append(f"max_iterations_rate={max_iter_rate:.2%} — agent looping without resolution")

    avg_turns = sum(len(s.turns) for s in sessions) / len(sessions)
    if avg_turns > thresholds.avg_turns_per_session:
        alerts.append(f"avg_turns_per_session={avg_turns:.1f} — sessions unusually long")

    tool_error_rate = sum(1 for t in all_turns if t["tool_errors"] > 0) / len(all_turns)
    if tool_error_rate > thresholds.tool_error_per_turn:
        alerts.append(f"tool_error_rate={tool_error_rate:.2%} — elevated tool failures")

    context_tokens = sorted(t["context_tokens"] for t in all_turns)
    p95_idx = int(len(context_tokens) * 0.95)
    p95_ctx = context_tokens[min(p95_idx, len(context_tokens) - 1)]
    if p95_ctx > thresholds.context_token_p95:
        alerts.append(f"context_p95={p95_ctx} tokens — approaching context limits")

    return alerts

from dataclasses import dataclass, field
from collections import Counter
import json

@dataclass
class ToolCallRecord:
    tool_name: str
    input_summary: str    # scrubbed / summarized — no raw PII
    status: str           # ok | error | timeout
    latency_ms: float
    error_class: str | None = None

@dataclass
class TurnToolStats:
    trace_id: str
    turn: int
    calls: list[ToolCallRecord] = field(default_factory=list)

    def add(self, name: str, input_summary: str, status: str,
            latency_ms: float, error_class: str | None = None) -> None:
        self.calls.append(ToolCallRecord(name, input_summary, status, latency_ms, error_class))

    def summary(self) -> dict:
        by_tool = Counter(c.tool_name for c in self.calls)
        errors = [c for c in self.calls if c.status != "ok"]
        return {
            "trace_id": self.trace_id,
            "turn": self.turn,
            "n_calls": len(self.calls),
            "tools_used": dict(by_tool),
            "n_errors": len(errors),
            "error_tools": [e.tool_name for e in errors],
            "avg_tool_latency_ms": (
                round(sum(c.latency_ms for c in self.calls) / len(self.calls), 1)
                if self.calls else 0.0
            ),
        }

def analyze_tool_patterns(stats: list[TurnToolStats]) -> dict:
    """Aggregate tool call patterns across many turns."""
    all_calls = [c for s in stats for c in s.calls]
    if not all_calls:
        return {}
    by_tool: dict[str, dict] = {}
    for call in all_calls:
        entry = by_tool.setdefault(call.tool_name, {"total": 0, "errors": 0, "latencies": []})
        entry["total"] += 1
        if call.status != "ok":
            entry["errors"] += 1
        entry["latencies"].append(call.latency_ms)
    return {
        tool: {
            "total": d["total"],
            "error_rate": round(d["errors"] / d["total"], 3),
            "avg_latency_ms": round(sum(d["latencies"]) / len(d["latencies"]), 1),
        }
        for tool, d in by_tool.items()
    }
